const SAFE_TEST_MODE = true;

const CODES = {
  reset: "\x1b[0m",
  red: "\x1b[31m",
  green: "\x1b[32m",
  yellow: "\x1b[33m",
  blue: "\x1b[34m",
  magenta: "\x1b[35m",
  cyan: "\x1b[36m",
  white: "\x1b[37m",
  bold: "\x1b[1m",
};

function red(str) {
  return CODES.red + str + CODES.reset;
}
function green(str) {
  return CODES.green + str + CODES.reset;
}
function blue(str) {
  return CODES.blue + str + CODES.reset;
}
function bold(str) {
  return CODES.bold + str + CODES.reset;
}

